import { useEffect, useState } from "react"
import "./moviesstyle.css"
import bookmark from "../src/assets/bookmark.png"
import { jsx } from "react/jsx-runtime"
function Movies() {
  
    
  
    const API_KEY_MOVIES = process.env.REACT_APP_API_KEY_MOVIES
    let [allmovies, changeallmovies] = useState([])
    let [fav, changefav] = useState()
    let [clicked, changeclicked] = useState("")
    let [bool, changebool] = useState(false)

    useEffect(() => {
        async function getmovies() {
            let movieslist = []
            for(let i = 1; i <= 5; i++) {
                let fetchmov = await fetch(`https://api.themoviedb.org/3/movie/popular?api_key=${API_KEY_MOVIES}&language=en-US&page=${i}`)
                let jsonfetchmov = await fetchmov.json()
        let res = jsonfetchmov.results.map((item) => {
            return <div key={item.id} id={`movie-card-${item.id}`}>
                <img
                    id={`movie-img-${item.id}`}
                    src={`https://image.tmdb.org/t/p/w500${item.backdrop_path}`}
                />
                <div id={`movie-title-row-${item.id}`}>
                    <p id={`movie-title-${item.id}`}>{item.original_title}</p>

                    <img
                        onClick={(e) => favthemovie(e)}
                        id={`movie-bookmark-${item.id}`}
                        src={bookmark}
                        alt="bookmark" 
                    />
                </div>
                <p id={`movie-pop-${item.id}`}>Popularity: {item.popularity}</p>
                <p id={`movie-vote-${item.id}`}>Rating: {item.vote_average}</p>
                <p id={`movie-date-${item.id}`}>Released: {item.release_date}</p>
            </div>
        })
        movieslist.push(res)
        }
        
        changeallmovies(movieslist.map(item => {
            return item
        }
        ))
        
        }
        getmovies()
    }, [])

    async function favthemovie(e) {
        let obj = {}
        let key = 0
        let arr = []
        arr.push(e.target.parentNode.parentNode.id)
        Array.of(e.target.parentNode.parentNode.children).forEach((i) => {
           for(const element of i) {
            arr.push(element.id)
                if(element.src) {
                    obj["img"] = element.src
                }
                else {
                    obj[key ++] = element.textContent
                }
           }
        })
        await fetch("http://localhost:5000/addfavmovie", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({allfavmoviedata: obj})
        })
        let sessionget = await fetch("http://localhost:5000/receivefavmovie", {
            method: "GET",
            headers: {"Content-Type":"application/json"},
            credentials: "include"
        })
        let jsonsessionget = await sessionget.json()
        let result = jsonsessionget.map((item, index) => {
            return  <div key={index} id={"movie-card-fav"}>
                <img
                    id={"movie-img-fav"}
                    src={`${item.img}`}
                />
                <div id={"movie-title-row-fav"}>
                    <p>{item[0]}</p>

                    <img
                        onClick={(e) => unfavthemovie(e)}
                        src={bookmark}
                        alt="bookmark" 
                    />
                </div>
                <p id={"movie-pop-fav"}>{item[1]}</p>
                <p id={"movie-vote-fav"}>{item[2]}</p>
                <p id={"movie-date-fav"}>{item[3]}</p>
            </div>
        })
        changefav(result)
    }
useEffect(() => {
      async function setvariable() {
                await fetch("http://localhost:5000/zerothevalues", {
                    method: "GET",
                    headers: {"Content-Type":"application/json"},
                    credentials: "include"
                })
        }
        setvariable()
    async function getdataback() {
    let sessionget = await fetch("http://localhost:5000/receivefavmovie", {
            method: "GET",
            headers: {"Content-Type":"application/json"},
            credentials: "include"
        })
    let jsonsessionget = await sessionget.json()
    if(jsonsessionget) {
        let result = jsonsessionget.map((item,index) => {
            return  <div id={"movie-card-fav"} key={index}>
                <img
                    id={"movie-img-fav"}
                    src={`${item.img}`}
                />
                <div id={"movie-title-row-fav"}>
                    <p>{item[0]}</p>

                    <img
                        onClick={(e) => unfavthemovie(e)} 
                        src={bookmark}
                        alt="bookmark" 
                    />
                </div>
                <p id={"movie-pop-fav"}>{item[1]}</p>
                <p id={"movie-vote-fav"}>{item[2]}</p>
                <p id={"movie-date-fav"}>{item[3]}</p>
            </div>
        })
        changefav(result)
    }
    }
    getdataback()
    
}, [])
async function unfavthemovie(e) {
    changebool((prev => !prev))
    changeclicked(e.target.parentNode.firstChild.textContent)
    
    await fetch("http://localhost:5000/removefavmovie", {
        method: "POST",
        headers: {"Content-Type":"application/json"},
        credentials: "include",
        body: JSON.stringify({clickedtounfav: e.target.parentNode.firstChild.textContent})
    })
}
useEffect(() => {
    async function removemovie() {
       
    if(fav) {
        let res = fav.filter((item) => {
            if(item.props.children[1].props.children[0].props.children !== clicked) {
                return item
            }
            
        })
        changefav(res)
    }
    }
   removemovie()
}, [bool])
    return (
  <>
    <div className="page">
      <div className="page-bg" aria-hidden="true"></div>

      <header className="page-header">
        <div className="page-header-inner">
          <div className="brand">
            <div className="brand-dot" />
            <div className="brand-text">
              <h1 className="brand-title">Movie Vault</h1>
              <p className="brand-subtitle">Popular picks + your saved favourites</p>
            </div>
          </div>

          <div className="page-hint">
            <span className="pill">Tip</span>
            <p>Scroll sideways. Tap the bookmark to save/remove.</p>
          </div>
        </div>
      </header>

      <div id="movies-shell">
        <div id="movies-header">
          <div className="section-bar">
            <p id="movies-title">Popular Movies</p>
            <div className="section-tools">
              <span className="dot"></span>
              <span className="dot"></span>
              <span className="dot"></span>
            </div>
          </div>
        </div>

        <div id="movies-row">{allmovies}</div>

        <div id="fav-shell">
          <div id="fav-header">
            <div className="section-bar">
              <p id="fav-title">Favourites</p>
              <div className="section-tools">
                <span className="dot"></span>
                <span className="dot"></span>
                <span className="dot"></span>
              </div>
            </div>
          </div>

          <div id="fav-row">{fav}</div>
        </div>
      </div>

      <footer className="page-footer">
        <p>Data from TMDB • Built locally</p>
      </footer>
    </div>
  </>
);
    }
export default Movies
